// WOA 悬浮注入 — 在 WPS协作 DevTools 控制台粘贴运行
// 再次运行可关闭
(function(){var id='cc-float-frame';var f=document.getElementById(id);if(f){f.remove();return;}f=document.createElement('iframe');f.id=id;var docUrl=prompt('输入当前文档 URL（如 https://365.kdocs.cn/l/xxx）：','');f.src='http://localhost:5174/panel?mode=float'+(docUrl?'&docUrl='+encodeURIComponent(docUrl)+'&docTitle='+encodeURIComponent(document.title||''):'');f.allow='clipboard-write';f.style.cssText='position:fixed;right:0;bottom:0;width:480px;height:640px;border:none;z-index:99999;background:transparent;';f.setAttribute('allowtransparency','true');document.body.appendChild(f);})();
